Template.CssStyles:
body {
    font-family: 'Helvetica', 'Arial', sans-serif;
    color: #334155;
    line-height: 1.5;
    margin: 0;
}

h1 {
    margin: 0;
    font-size: 28pt;
    font-weight: 800;
    color: #1a1a1a;
    text-transform: uppercase;
}

.subtitle {
    font-size: 14pt;
    color: #3b82f6;
    font-weight: 500;
}

.section {
    margin-bottom: 25px;
}

.section h2 {
    font-size: 11pt;
    font-weight: 700;
    text-transform: uppercase;
    color: #1a1a1a;
    border-bottom: 2px solid #e2e8f0;
    padding-bottom: 5px;
    margin-bottom: 10px;
}

.content {
    font-size: 10pt;
    white-space: pre-wrap;
    color: #475569;
}
